#!/bin/bash
pkill anvil
anvil &
sleep 2

PRIVATE_KEY=0xac0974bec39a17e36ba4a6b4d238ff944bacb478cbed5efcae784d7bf4f2ff80
RPC=http://localhost:8545

# Deploy TSender
cast send --private-key $PRIVATE_KEY --rpc-url $RPC --create 

# Deploy Mock Token using forge (properly compiled)
cd ../contracts
forge script script/Deploy.s.sol:Deploy \
  --rpc-url $RPC \
  --private-key $PRIVATE_KEY \
  --broadcast
cd ../my-app

echo "Done! TSender at 0x5FbDB2315678afecb367f032d93F642f64180aa3"
echo "Token will be at a new address - check forge output above"